static void rl(float*d,int n){for(int i=0;i<n;i++)if(d[i]<0)d[i]=0;}
static void mp(const float*i,float*o,int H,int W,int C){
int oH=H/2,oW=W/2,iHW=H*W,oHW=oH*oW;for(int c=0;c<C;c++)for(int y=0;y<oH;y++)for(int x=0;x<oW;x++){int iy=y*2,ix=x*2;float v=i[c*iHW+iy*W+ix];v=max(v,i[c*iHW+iy*W+ix+1]);v=max(v,i[c*iHW+(iy+1)*W+ix]);v=max(v,i[c*iHW+(iy+1)*W+ix+1]);o[c*oHW+y*oW+x]=v;}}
